from abc import ABC, abstractmethod

class Payment(ABC):
    @abstractmethod
    def process_payment(self, amount_to_charge):
        pass

    @abstractmethod
    def validate_payment(self, amount_to_charge):
        pass

class PaymentWallet(Payment):
    def __init__(self, id, amount, currency, wallet_id):
        self.id = id
        self.amount = amount
        self.currency = currency
        self.wallet_id = wallet_id

    def validate_wallet(self):
        return bool(self.wallet_id)

    def charge_wallet(self, amount_to_charge):
        if amount_to_charge <= self.amount:
            self.amount -= amount_to_charge
            return True
        return False

    def process_payment(self, amount_to_charge):
        if self.validate_wallet() and self.charge_wallet(amount_to_charge):
            print("Payment processed successfully.")
        print("Payment failed.")

    def validate_payment(self, amount_to_charge):
        return self.validate_wallet() and self.charge_wallet(amount_to_charge)

